function LxUtf8.cc_len(s)
    local left = string.len(s)
    local cnt  = 0
    local arr  = {0, 0xc0, 0xe0, 0xf0, 0xf8, 0xfc}
    while left > 0 do
        local tmp = string.byte(s, -left)
        local i   = #arr
        while arr[i] do
            if tmp >= arr[i] then
                left = left - i
                break
            end
            i = i - 1
        end
        cnt = cnt + 1
    end
    return cnt
end

function LxUtf8.len(s)
    s = s or ""
    local len = 0
    for _ in _byte_indices(s) do
        len = len + 1
    end
    return len
end

function LxUtf8.cnLen(s)
    s = s or ""

    local charLen = string.len(s)
    if (charLen <= 0) then
        return 0
    end

    local len = 0
    local previ = 1
    --第一个ci必定是1，第一个字是没有进行长度统计
    --在循环结束之后，补回统计
    for ci in _byte_indices(s) do
        if (ci > 1) then
            if (ci - previ) > 1 then -- 长度递增大于等于2， 不是ascii， 当成汉字处理
                len = len + 2
            else
                len = len + 1
            end
        end
        previ = ci
    end

    if (charLen - previ) > 1 then
        len = len + 2
    else
        len = len + 1
    end
    return len
end

function LxUtf8.sub(s, start_ci, end_ci)
    return _sub(s, start_ci, end_ci)
